// Pull metadata from headers/query so the caller can label speakers and stitch chunks.
const headers = $json.headers || {};
const query   = $json.query   || {};
const session_id     = headers['x-session-id']     || query.session_id     || 'session-' + Date.now();
const chunk_index    = parseInt(headers['x-chunk-index'] || query.chunk_index || '0', 10);
const speaker_hint   = headers['x-speaker']        || query.speaker        || ''; // optional: from VAD on client
const language_code  = headers['x-language']       || query.language_code  || 'unknown';
const model_name     = headers['x-model']          || query.model          || 'saarika:v2.5';

return [{
  json: {
    session_id,
    chunk_index,
    speaker_hint,
    language_code,
    model_name,
    received_at: new Date().toISOString()
  },
  binary: $binary
}];

// Build a running diarization label from the speaker_hint OR rotate when energy/silence boundary suggests a new speaker.
// For zero-config use, rotate speaker label every Nth chunk (cheap demo-grade diarization).
const sarvam = $json;
const meta = $('Parse chunk metadata').first().json;

const transcript = sarvam.transcript || '';
const lang = sarvam.language_code || meta.language_code;
const error = sarvam.error || null;

// Cheap speaker assignment:
//   - if client passed x-speaker / ?speaker= use that verbatim
//   - else rotate "Speaker 1/2/3" by mod 3 of chunk_index
let speaker = (meta.speaker_hint && String(meta.speaker_hint).trim()) || `Speaker ${(meta.chunk_index % 3) + 1}`;

const line = transcript ? `${speaker}: ${transcript}` : '';

return [{
  json: {
    session_id: meta.session_id,
    chunk_index: meta.chunk_index,
    speaker,
    language_code: lang,
    transcript,
    line,
    received_at: meta.received_at,
    transcribed_at: new Date().toISOString(),
    sarvam_request_id: sarvam.request_id || null,
    error
  }
}];
